    {"offset": {"line": 4, "column": 0}, "map": {"version":3,"sources":["file:///C:/Users/LWRSH/Documents/Loveworld-Singers-Rehearsal-Hub-Portal-Zonal-Mode/src/utils/media-cache.ts"],"sourcesContent":["// Media caching utility with zone-specific support\r\ninterface Media {\r\n  id: string\r\n  title: string\r\n  description?: string\r\n  type: string\r\n  [key: string]: any\r\n}\r\n\r\nconst CACHE_KEY_BASE = 'media-cache'\r\nconst CACHE_DURATION = 10 * 60 * 1000 // 10 minutes (media changes less frequently)\r\n\r\ninterface CachedData {\r\n  data: Media[]\r\n  timestamp: number\r\n}\r\n\r\n// Get cache key with optional zone suffix\r\nfunction getCacheKey(zoneType?: string): string {\r\n  return zoneType ? `${CACHE_KEY_BASE}-${zoneType}` : CACHE_KEY_BASE\r\n}\r\n\r\nexport class MediaCache {\r\n  // Save media to localStorage (with optional zone-specific key)\r\n  static saveMedia(media: Media[], zoneType?: string): void {\r\n    try {\r\n      const cached: CachedData = {\r\n        data: media,\r\n        timestamp: Date.now()\r\n      }\r\n      const key = getCacheKey(zoneType)\r\n      localStorage.setItem(key, JSON.stringify(cached))\r\n      console.log(`💾 Cached ${media.length} media items (${zoneType || 'default'})`)\r\n    } catch (error) {\r\n      console.error('Failed to cache media:', error)\r\n    }\r\n  }\r\n\r\n  // Load media from localStorage (with optional zone-specific key)\r\n  static loadMedia(zoneType?: string): Media[] | null {\r\n    try {\r\n      const key = getCacheKey(zoneType)\r\n      const cached = localStorage.getItem(key)\r\n      if (!cached) {\r\n        console.log(`📭 No cached media found (${zoneType || 'default'})`)\r\n        return null\r\n      }\r\n\r\n      const parsed: CachedData = JSON.parse(cached)\r\n      \r\n      // Check if cache is still valid\r\n      const age = Date.now() - parsed.timestamp\r\n      if (age > CACHE_DURATION) {\r\n        console.log(`⏰ Cached media expired (${zoneType || 'default'})`)\r\n        this.clearMedia(zoneType)\r\n        return null\r\n      }\r\n\r\n      console.log(`⚡ Cache hit: ${parsed.data.length} media items loaded instantly (${zoneType || 'default'})`)\r\n      return parsed.data\r\n    } catch (error) {\r\n      console.error('Failed to load cached media:', error)\r\n      return null\r\n    }\r\n  }\r\n\r\n  // Clear cached media (with optional zone-specific key)\r\n  static clearMedia(zoneType?: string): void {\r\n    try {\r\n      const key = getCacheKey(zoneType)\r\n      localStorage.removeItem(key)\r\n      console.log(`🗑️ Cleared cached media (${zoneType || 'default'})`)\r\n    } catch (error) {\r\n      console.error('Failed to clear cached media:', error)\r\n    }\r\n  }\r\n  \r\n  // Clear all media caches (both HQ and regular)\r\n  static clearAllMedia(): void {\r\n    try {\r\n      localStorage.removeItem(getCacheKey())\r\n      localStorage.removeItem(getCacheKey('hq'))\r\n      localStorage.removeItem(getCacheKey('regular'))\r\n      console.log('🗑️ Cleared all cached media')\r\n    } catch (error) {\r\n      console.error('Failed to clear all cached media:', error)\r\n    }\r\n  }\r\n}\r\n"],"names":[],"mappings":"AAAA,mDAAmD;;;;;AASnD,MAAM,iBAAiB;AACvB,MAAM,iBAAiB,KAAK,KAAK,KAAK,6CAA6C;;AAOnF,0CAA0C;AAC1C,SAAS,YAAY,QAAiB;IACpC,OAAO,WAAW,AAAC,GAAoB,OAAlB,gBAAe,KAAY,OAAT,YAAa;AACtD;AAEO,MAAM;IACX,+DAA+D;IAC/D,OAAO,UAAU,KAAc,EAAE,QAAiB,EAAQ;QACxD,IAAI;YACF,MAAM,SAAqB;gBACzB,MAAM;gBACN,WAAW,KAAK,GAAG;YACrB;YACA,MAAM,MAAM,YAAY;YACxB,aAAa,OAAO,CAAC,KAAK,KAAK,SAAS,CAAC;YACzC,QAAQ,GAAG,CAAC,AAAC,aAAyC,OAA7B,MAAM,MAAM,EAAC,kBAAsC,OAAtB,YAAY,WAAU;QAC9E,EAAE,OAAO,OAAO;YACd,QAAQ,KAAK,CAAC,0BAA0B;QAC1C;IACF;IAEA,iEAAiE;IACjE,OAAO,UAAU,QAAiB,EAAkB;QAClD,IAAI;YACF,MAAM,MAAM,YAAY;YACxB,MAAM,SAAS,aAAa,OAAO,CAAC;YACpC,IAAI,CAAC,QAAQ;gBACX,QAAQ,GAAG,CAAC,AAAC,6BAAkD,OAAtB,YAAY,WAAU;gBAC/D,OAAO;YACT;YAEA,MAAM,SAAqB,KAAK,KAAK,CAAC;YAEtC,gCAAgC;YAChC,MAAM,MAAM,KAAK,GAAG,KAAK,OAAO,SAAS;YACzC,IAAI,MAAM,gBAAgB;gBACxB,QAAQ,GAAG,CAAC,AAAC,2B